```go
package analytics

import (
	"database/sql"
	"math"
	"sort"
	"time"
)

// ReplyLatency computes response-time statistics from reply_events joined with enrollments.
func ReplyLatency(d *sql.DB) (*ReplyLatencyStats, error) {
	rows, err := d.Query(`
		SELECT re.classification, re.occurred_at, se.last_sent_at
		FROM reply_events re
		JOIN sequence_enrollments se ON se.id = re.enrollment_id
		WHERE se.last_sent_at != '' AND re.occurred_at != ''
	`)
	if err != nil {
		return &ReplyLatencyStats{ByClass: map[string]float64{}}, err
	}
	defer rows.Close()

	type latencyRow struct {
		classification string
		hours          float64
	}

	var all []latencyRow
	byClass := map[string][]float64{}

	for rows.Next() {
		var class, occurredAt, lastSentAt string
		if err := rows.Scan(&class, &occurredAt, &lastSentAt); err != nil {
			continue
		}
		tReply, err1 := time.Parse(time.RFC3339, occurredAt)
		tSent, err2 := time.Parse(time.RFC3339, lastSentAt)
		if err1 != nil || err2 != nil {
			continue
		}
		hours := tReply.Sub(tSent).Hours()
		if hours < 0 {
			continue
		}
		hours = math.Round(hours*10) / 10
		all = append(all, latencyRow{classification: class, hours: hours})
		byClass[class] = append(byClass[class], hours)
	}

	stats := &ReplyLatencyStats{
		Count:   len(all),
		ByClass: map[string]float64{},
	}
	if len(all) == 0 {
		return stats, nil
	}

	hours := make([]float64, len(all))
	for i, r := range all {
		hours[i] = r.hours
	}
	sort.Float64s(hours)

	stats.MedianHours = median(hours)
	stats.P90Hours = percentile(hours, 90)
	stats.MinHours = hours[0]
	stats.MaxHours = hours[len(hours)-1]

	for class, vals := range byClass {
		sort.Float64s(vals)
		stats.ByClass[class] = median(vals)
	}

	return stats, nil
}

func median(sorted []float64) float64 {
	n := len(sorted)
	if n == 0 {
		return 0
	}
	if n%2 == 0 {
		return (sorted[n/2-1] + sorted[n/2]) / 2
	}
	return sorted[n/2]
}

func percentile(sorted []float64, p int) float64 {
	n := len(sorted)
	if n == 0 {
		return 0
	}
	idx := int(math.Ceil(float64(p)/100*float64(n))) - 1
	if idx < 0 {
		idx = 0
	}
	if idx >= n {
		idx = n - 1
	}
	return sorted[idx]
}
```

