```go
package analytics

import (
	"database/sql"
	"fmt"
	"math"
	"strings"
)

// WinPatterns compares message characteristics (word count, question count)
// between emails that got replies and those that didn't.
func WinPatterns(d *sql.DB) (*WinningPatterns, error) {
	rows, err := d.Query(`
		SELECT se.initial_body, CASE WHEN re.id IS NOT NULL THEN 1 ELSE 0 END AS got_reply
		FROM sequence_enrollments se
		LEFT JOIN reply_events re ON re.enrollment_id = se.id
		WHERE se.initial_body != ''
	`)
	if err != nil {
		return &WinningPatterns{}, err
	}
	defer rows.Close()

	var repliedWords, noReplyWords []int
	var repliedQs, noReplyQs []int

	for rows.Next() {
		var body string
		var gotReply int
		if err := rows.Scan(&body, &gotReply); err != nil {
			continue
		}

		words := len(strings.Fields(body))
		questions := strings.Count(body, "?")

		if gotReply == 1 {
			repliedWords = append(repliedWords, words)
			repliedQs = append(repliedQs, questions)
		} else {
			noReplyWords = append(noReplyWords, words)
			noReplyQs = append(noReplyQs, questions)
		}
	}

	wp := &WinningPatterns{}
	wp.RepliedAvgWords = avgInt(repliedWords)
	wp.NoReplyAvgWords = avgInt(noReplyWords)
	wp.RepliedAvgQuestions = avgFloat(repliedQs)
	wp.NoReplyAvgQuestions = avgFloat(noReplyQs)

	if wp.RepliedAvgWords > 0 {
		low := int(math.Round(float64(wp.RepliedAvgWords) * 0.7))
		high := int(math.Round(float64(wp.RepliedAvgWords) * 1.3))
		qStr := "1"
		if wp.RepliedAvgQuestions >= 1.5 {
			qStr = "1-2"
		}
		wp.SweetSpot = fmt.Sprintf("%d-%d words, %s questions", low, high, qStr)
	}

	return wp, nil
}

func avgInt(vals []int) int {
	if len(vals) == 0 {
		return 0
	}
	sum := 0
	for _, v := range vals {
		sum += v
	}
	return int(math.Round(float64(sum) / float64(len(vals))))
}

func avgFloat(vals []int) float64 {
	if len(vals) == 0 {
		return 0
	}
	sum := 0
	for _, v := range vals {
		sum += v
	}
	return math.Round(float64(sum)/float64(len(vals))*10) / 10
}
```

