package analytics

import (
	"database/sql"
	"math"
	"sort"
)

// PersonaRates computes reply rates grouped by contact title (job title).
// Contacts with no title are grouped as "Unknown".
// Results are sorted by rate descending.
func PersonaRates(d *sql.DB) ([]PersonaRate, error) {
	rows, err := d.Query(`
		SELECT
			CASE WHEN c.title = '' OR c.title IS NULL THEN 'Unknown' ELSE c.title END AS persona,
			COUNT(DISTINCT se.contact_email) AS contacted,
			COUNT(DISTINCT re.contact_email) AS replied
		FROM sequence_enrollments se
		JOIN contacts c ON lower(c.email) = lower(se.contact_email)
		LEFT JOIN reply_events re ON re.enrollment_id = se.id
		GROUP BY persona
		ORDER BY contacted DESC
	`)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var rates []PersonaRate
	for rows.Next() {
		var pr PersonaRate
		if err := rows.Scan(&pr.Title, &pr.Contacted, &pr.Replied); err != nil {
			continue
		}
		if pr.Contacted > 0 {
			pr.Rate = math.Round(float64(pr.Replied)/float64(pr.Contacted)*100) / 100
		}
		rates = append(rates, pr)
	}

	sort.Slice(rates, func(i, j int) bool {
		return rates[i].Rate > rates[j].Rate
	})

	return rates, nil
}
