package analytics

import (
	"database/sql"
	"math"
	"sort"
)

// TimeOfDayPatterns computes reply effectiveness by the hour the email was sent.
// Uses enrollment last_sent_at as send time (hour extracted in UTC).
func TimeOfDayPatterns(d *sql.DB) (*TimePatterns, error) {
	rows, err := d.Query(`
		SELECT
			CAST(strftime('%%H', se.last_sent_at) AS INTEGER) AS send_hour,
			COUNT(DISTINCT se.id) AS sent,
			COUNT(DISTINCT re.id) AS replied
		FROM sequence_enrollments se
		LEFT JOIN reply_events re ON re.enrollment_id = se.id
		WHERE se.last_sent_at != ''
		GROUP BY send_hour
		ORDER BY send_hour
	`)
	if err != nil {
		return &TimePatterns{}, err
	}
	defer rows.Close()

	var buckets []HourBucket
	for rows.Next() {
		var hb HourBucket
		if err := rows.Scan(&hb.Hour, &hb.Sent, &hb.Replied); err != nil {
			continue
		}
		if hb.Sent > 0 {
			hb.Rate = math.Round(float64(hb.Replied)/float64(hb.Sent)*100) / 100
		}
		buckets = append(buckets, hb)
	}

	tp := &TimePatterns{Buckets: buckets}
	if len(buckets) == 0 {
		return tp, nil
	}

	// Sort by rate to find best/worst (only include hours with >= 2 sends for significance)
	type ranked struct {
		hour int
		rate float64
	}
	var significant []ranked
	for _, b := range buckets {
		if b.Sent >= 2 {
			significant = append(significant, ranked{hour: b.Hour, rate: b.Rate})
		}
	}
	sort.Slice(significant, func(i, j int) bool {
		return significant[i].rate > significant[j].rate
	})

	for i, r := range significant {
		if i < 3 {
			tp.BestSendHours = append(tp.BestSendHours, r.hour)
		}
	}
	for i := len(significant) - 1; i >= 0 && len(tp.WorstSendHours) < 3; i-- {
		if significant[i].rate < significant[0].rate {
			tp.WorstSendHours = append(tp.WorstSendHours, significant[i].hour)
		}
	}

	return tp, nil
}
