- [ ] **Step 3: Write implementation**

The insight picker ranks by actionability. Priority order:
1. Winning patterns (if data shows clear signal) - tells user what to change NOW
2. Persona rates (if one persona is significantly better) - tells user who to target
3. Time patterns (if clear best/worst hours) - tells user when to send
4. Reply latency (always interesting but least actionable)

```go
package analytics

import (
	"database/sql"
	"fmt"
	"math"
	"time"
)

// Summary computes all four analytics metrics and picks the single most
// actionable insight for the banner.
func Summary(d *sql.DB) (*AnalyticsSummary, error) {
	s := &AnalyticsSummary{
		GeneratedAt: time.Now().Format(time.RFC3339),
	}

	latency, _ := ReplyLatency(d)
	s.ReplyLatency = latency

	personas, _ := PersonaRates(d)
	s.PersonaRates = personas

	tp, _ := TimeOfDayPatterns(d)
	s.TimePatterns = tp

	wp, _ := WinPatterns(d)
	s.WinningPatterns = wp

	s.TopInsight = pickTopInsight(s)
	return s, nil
}

func pickTopInsight(s *AnalyticsSummary) string {
	// 1. Winning patterns: if replied emails are significantly shorter, say so
	if wp := s.WinningPatterns; wp != nil && wp.RepliedAvgWords > 0 && wp.NoReplyAvgWords > 0 {
		if wp.NoReplyAvgWords > 0 {
			ratio := float64(wp.RepliedAvgWords) / float64(wp.NoReplyAvgWords)
			if ratio < 0.7 {
				return fmt.Sprintf("Shorter emails win: replies avg %d words vs %d for no-reply",
					wp.RepliedAvgWords, wp.NoReplyAvgWords)
			}
		}
	}

	// 2. Persona rates: if top persona has significantly higher rate than average
	if len(s.PersonaRates) >= 2 {
		top := s.PersonaRates[0]
		if top.Contacted >= 3 && top.Rate > 0 {
			var totalContacted, totalReplied int
			for _, p := range s.PersonaRates {
				totalContacted += p.Contacted
				totalReplied += p.Replied
			}
			avgRate := float64(totalReplied) / float64(totalContacted)
			if top.Rate > avgRate*1.5 {
				return fmt.Sprintf("%ss reply %.0f%% vs %.0f%% avg - double down",
					top.Title, top.Rate*100, avgRate*100)
			}
		}
	}

	// 3. Time patterns: if there's a clear best hour
	if tp := s.TimePatterns; tp != nil && len(tp.BestSendHours) > 0 && len(tp.Buckets) >= 3 {
		var bestBucket HourBucket
		for _, b := range tp.Buckets {
			if b.Hour == tp.BestSendHours[0] {
				bestBucket = b
			}
		}
		if bestBucket.Rate > 0.3 {
			return fmt.Sprintf("Best send time: %d:00 (%.0f%% reply rate)",
				bestBucket.Hour, bestBucket.Rate*100)
		}
	}

	// 4. Reply latency: if we have data
	if lat := s.ReplyLatency; lat != nil && lat.Count > 0 {
		if lat.MedianHours < 24 {
			return fmt.Sprintf("Replies come in ~%.0fh (median) - follow up after %.0fh of silence",
				lat.MedianHours, math.Max(lat.P90Hours, 24))
		}
		return fmt.Sprintf("Replies take ~%.0fh median - patience pays off", lat.MedianHours)
	}

	return ""
}
